import { createContext, useContext, useEffect, useState } from "react";

const BASE_URL = "http://localhost:9000";

// 1. CREATE CONTEXT
const CitiesContext = createContext();

// 2. CREATE PROVIDER COMPONENT
function CitiesProvider({ children }) {
  const [cities, setCities] = useState([]);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(function () {
    async function fetchCities() {
      try {
        setIsLoading(true);
        const res = await fetch(`${BASE_URL}/cities`);
        const data = await res.json();
        setCities(data);
      } catch (err) {
        console.error("Error fetching cities:", err);
      } finally {
        setIsLoading(false);
      }
    }
    fetchCities();
  }, []);

  return (
    <CitiesContext.Provider value={{ cities, isLoading }}>
      {children}
    </CitiesContext.Provider>
  );
}

// 3. CREATE CUSTOM HOOK TO CONSUME CONTEXT
function useCities() {
  const context = useContext(CitiesContext);
  if (context === undefined)
    throw new Error("CitiesContext was used outside of the CitiesProvider");
  return context;
}

export { CitiesProvider, useCities };

import { createContext, useContext, useEffect, useState } from "react";

const BASE_URL = "http://localhost:9000";

// 1. CREATE CONTEXT
const CitiesContext = createContext();

// 2. CREATE PROVIDER COMPONENT
function CitiesProvider({ children }) {
  const [cities, setCities] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [currentCity, setCurrentCity] = useState({});

  useEffect(function () {
    async function fetchCities() {
      try {
        setIsLoading(true);
        const res = await fetch(`${BASE_URL}/cities`);
        const data = await res.json();
        setCities(data);
      } catch (err) {
        console.error("Error fetching cities:", err);
      } finally {
        setIsLoading(false);
      }
    }
    fetchCities();
  }, []);

  async function getCity(id) {
    try {
      setIsLoading(true);
      const res = await fetch(`${BASE_URL}/cities/${id}`);
      const data = await res.json();
      setCurrentCity(data);
    } catch (err) {
      console.error("Error fetching city:", err);
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <CitiesContext.Provider value={{ cities, isLoading, currentCity, getCity }}>
      {children}
    </CitiesContext.Provider>
  );
}

// 3. CREATE CUSTOM HOOK TO CONSUME CONTEXT
function useCities() {
  const context = useContext(CitiesContext);
  if (context === undefined)
    throw new Error("CitiesContext was used outside of the CitiesProvider");
  return context;
}

export { CitiesProvider, useCities };

import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import styles from "./City.module.css";
import Spinner from "./Spinner.jsx";
import { emojiToCountryCode } from "./CityItem.jsx";
import Button from "./Button.jsx";

const BASE_URL = "http://localhost:9000";

function formatDate(date) {
    return new Intl.DateTimeFormat("en", {
        day: "numeric",
        month: "long",
        year: "numeric",
        weekday: "long",
    }).format(new Date(date));
}

export default function City() {
    const { id } = useParams();
    const navigate = useNavigate();
    const [city, setCity] = useState(null);
    const [isLoading, setIsLoading] = useState(false);

    useEffect(function () {
        async function fetchCity() {
            try {
                setIsLoading(true);
                const res = await fetch(`${BASE_URL}/cities/${id}`);
                const data = await res.json();
                setCity(data);
            } catch (err) {
                console.error("Error fetching city:", err);
            } finally {
                setIsLoading(false);
            }
        }
        fetchCity();
    }, [id]);

    if (isLoading) return <Spinner />;
    if (!city) return null;

    const { cityName, emoji, date, notes } = city;
    const countryCode = emojiToCountryCode(emoji);

    return (
        <div className={styles.city}>
            <div className={styles.row}>
                <h6>City name</h6>
                <h3>
                    <img
                        src={`https://flagcdn.com/24x18/${countryCode}.png`}
                        alt={cityName}
                    />
                    {cityName}
                </h3>
            </div>

            <div className={styles.row}>
                <h6>You went to {cityName} on</h6>
                <p>{formatDate(date)}</p>
            </div>

            {notes && (
                <div className={styles.row}>
                    <h6>Your notes</h6>
                    <p>{notes}</p>
                </div>
            )}

            <div className={styles.row}>
                <h6>Learn more</h6>
                <a
                    href={`https://en.wikipedia.org/wiki/${cityName}`}
                    target="_blank"
                    rel="noreferrer"
                >
                    Check out {cityName} on Wikipedia &rarr;
                </a>
            </div>

            <div>
                <Button variant="back" onClick={() => navigate(-1)}>&larr; Back</Button>
            </div>
        </div>
    );
}

import { useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import styles from "./City.module.css";
import Spinner from "./Spinner.jsx";
import { emojiToCountryCode } from "./CityItem.jsx";
import Button from "./Button.jsx";
import { useCities } from "../contexts/CitiesContext.jsx";

function formatDate(date) {
    return new Intl.DateTimeFormat("en", {
        day: "numeric",
        month: "long",
        year: "numeric",
        weekday: "long",
    }).format(new Date(date));
}

export default function City() {
    const { id } = useParams();
    const navigate = useNavigate();
    const { currentCity, getCity, isLoading } = useCities();

    useEffect(function () {
        getCity(id);
    }, [id]);

    if (isLoading) return <Spinner />;
    if (!currentCity.id) return null;

    const { cityName, emoji, date, notes } = currentCity;
    const countryCode = emojiToCountryCode(emoji);

    return (
        <div className={styles.city}>
            <div className={styles.row}>
                <h6>City name</h6>
                <h3>
                    <img
                        src={`https://flagcdn.com/24x18/${countryCode}.png`}
                        alt={cityName}
                    />
                    {cityName}
                </h3>
            </div>

            <div className={styles.row}>
                <h6>You went to {cityName} on</h6>
                <p>{formatDate(date)}</p>
            </div>

            {notes && (
                <div className={styles.row}>
                    <h6>Your notes</h6>
                    <p>{notes}</p>
                </div>
            )}

            <div className={styles.row}>
                <h6>Learn more</h6>
                <a
                    href={`https://en.wikipedia.org/wiki/${cityName}`}
                    target="_blank"
                    rel="noreferrer"
                >
                    Check out {cityName} on Wikipedia &rarr;
                </a>
            </div>

            <div>
                <Button variant="back" onClick={() => navigate(-1)}>&larr; Back</Button>
            </div>
        </div>
    );
}

import styles from "./CityItem.module.css";
import { Link } from "react-router-dom";

function formatDate(date) {
    return new Intl.DateTimeFormat("en", {
        day: "numeric",
        month: "long",
        year: "numeric",
    }).format(new Date(date));
}

export function emojiToCountryCode(emoji) {
    return [...emoji]
        .map((char) => String.fromCharCode(char.codePointAt(0) - 127397))
        .join("")
        .toLowerCase();
}

export default function CityItem({ city }) {
    const { cityName, emoji, date, id } = city;
    const countryCode = emojiToCountryCode(emoji);

    return (
        <li >
            <Link to={`${id}`} className={styles.cityItem}>
                <img
                    src={`https://flagcdn.com/24x18/${countryCode}.png`}
                    alt={cityName}
                    className={styles.emoji}
                />
                <h3 className={styles.name}>{cityName}</h3>
                <time className={styles.date}>({formatDate(date)})</time>
                <button className={styles.deleteBtn}>&times;</button>
            </Link>
        </li>
    );
}

